## 2. gRPC Proto

파일 위치: `proto/src/main/proto/profile/profile_service.proto`

```protobuf
syntax = "proto3";

package maum.profile.v1;

option java_package = "com.maum.backend.proto.profile.v1";
option java_multiple_files = true;

// ─────────────────────────────────────────────
// 열거형
// ─────────────────────────────────────────────

enum Gender {
    GENDER_UNSPECIFIED = 0;
    GENDER_MALE = 1;
    GENDER_FEMALE = 2;
    GENDER_OTHER = 3;
}

// ─────────────────────────────────────────────
// 메시지 타입
// ─────────────────────────────────────────────

message Profile {
    string user_id = 1;
    string nickname = 2;
    optional string bio = 3;
    optional string profile_image_url = 4;
    Gender gender = 5;
    optional int32 birth_year = 6;
    optional string region = 7;
    string updated_at = 8;
}

// Partial Update를 위해 google.protobuf.FieldMask 활용
message UpdateProfileRequest {
    string user_id = 1;
    optional string nickname = 2;
    optional string bio = 3;
    optional string profile_image_url = 4;
    optional Gender gender = 5;
    optional int32 birth_year = 6;
    optional string region = 7;
}

message UpdateProfileResponse {
    Profile profile = 1;
}

// ─────────────────────────────────────────────
// 서비스 정의
// ─────────────────────────────────────────────

service ProfileService {
    rpc UpdateProfile(UpdateProfileRequest) returns (UpdateProfileResponse);
}
```

