## 5. gRPC Server Service

파일 위치: `profile-service/src/main/kotlin/com/maum/backend/profile/service/ProfileGrpcService.kt`

```kotlin
@GrpcService
class ProfileGrpcService(
    private val profileCommandService: ProfileCommandService,
) : ProfileServiceGrpc.ProfileServiceImplBase() {

    override fun updateProfile(
        request: UpdateProfileRequest,
        responseObserver: StreamObserver<UpdateProfileResponse>,
    ) {
        val updatedProfile = profileCommandService.updateProfile(request)

        val response = UpdateProfileResponse.newBuilder()
            .setProfile(updatedProfile.toProto())
            .build()

        responseObserver.onNext(response)
        responseObserver.onCompleted()
    }
}
```

