## 6. Validation 고려사항

```kotlin
// profile-service/src/main/kotlin/com/maum/backend/profile/service/ProfileCommandService.kt

@Service
class ProfileCommandService(
    private val profileRepository: ProfileRepository,
) {
    fun updateProfile(request: UpdateProfileRequest): Profile {
        val profile = profileRepository.findByUserId(request.userId)
            ?: throw ProfileNotFoundException(request.userId)

        // nickname 검증: 2~20자, 한글/영문/숫자만 허용
        request.nickname?.let { nickname ->
            require(nickname.length in 2..20) { "닉네임은 2자 이상 20자 이하여야 합니다." }
            require(nickname.matches(Regex("^[가-힣a-zA-Z0-9]+$"))) { "닉네임에 특수문자를 사용할 수 없습니다." }
        }

        // bio 검증: 최대 200자
        request.bio?.let { bio ->
            require(bio.length <= 200) { "자기소개는 200자 이하여야 합니다." }
        }

        // birthYear 검증: 1900~현재년도
        request.birthYear?.let { year ->
            val currentYear = LocalDate.now().year
            require(year in 1900..currentYear) { "올바른 출생연도를 입력해주세요." }
        }

        // gender는 최초 설정 후 변경 불가 정책
        if (request.hasGender() && profile.gender != null) {
            throw GenderAlreadySetException()
        }

        return profileRepository.save(profile.applyUpdate(request))
    }
}
```

